      <span style={{ fontSize: 11, fontWeight: 600, color: '#059669', background: '#ecfdf5',
                     borderRadius: 999, padding: '1px 8px' }}>{data.status}</span>
    </div>
  );
}

export default function HtmlNodesDemo() {
