import type { DiagramInstance } from '@grafloria/react';
import { GrafloriaFlow } from '@grafloria/react';
import { markReady } from '../ready';

const nodes = [
  { id: 'win',  position: { x: 300, y: 200 }, size: { width: 240, height: 120 }, label: 'window body' },
  { id: 'grip', position: { x: 300, y: 200 }, size: { width: 240, height: 28 },  label: '⠿ title bar (drag me)' },
];
const edges: any[] = [];

/** A designated grip drags its parent — and ONLY the grip: the body still
 *  selects but no longer drags. The grip is made a drag-handle child INSIDE the
 *  parent's top strip through the live model. */
export default function DragHandleDemo() {
  const onInit = (instance: DiagramInstance) => {
    const grip = instance.getModel().getNode('grip');
    if (grip) {
      grip.setParent('win');
      grip.setPosition(0, 0);               // local → covers the parent's top 28px
      grip.setBehavior({ dragHandler: { isDragHandler: true } });
      instance.renderNow();
    }
    markReady();
  };
  return (
    <div style={{ height: '100vh' }}>
      <GrafloriaFlow defaultNodes={nodes} defaultEdges={edges} onInit={onInit} />
    </div>
  );
}

nodes/easy-connect.text:
import type { DiagramInstance } from '@grafloria/react';
import { GrafloriaFlow } from '@grafloria/react';
import { registerTool, SnapController } from '@grafloria/element';
import { markReady } from '../ready';

const nodes = [
  { id: 'a', position: { x: 100, y: 150 }, size: { width: 200, height: 120 }, label: 'A · press anywhere' },
  { id: 'b', position: { x: 560, y: 150 }, size: { width: 200, height: 120 }, label: 'B · release anywhere' },
];
const edges: any[] = [];

/** The whole node is a connection handle: press anywhere on one node, release
 *  anywhere on another, and they wire up — no tiny port to aim at. Wired through
 *  the public registerTool seam, committing a real link via the link command. */
export default function EasyConnectDemo() {
  const onInit = (instance: DiagramInstance) => {
    const model = instance.getModel();
    const engine = instance.getEngine() as any;
    const snap = new SnapController();
    let src: any = null;
    registerTool({
      id: 'demo-easy-connect',
      priority: 10,
      hitTest: (_e: any, hit: any) => !!hit.node,
      onPointerDown: (_e: any, hit: any) => { src = hit.node; },
      onPointerUp: (e: any) => {
        if (!src) return;
        const tgt = (model as any).getNodeAtPosition(e.world.x, e.world.y);
        if (tgt && tgt.id !== src.id) {
          const candidate = {
            sourcePort: src.getPortBySide('right') ?? src.getPorts()[0],
            targetPort: tgt.getPortBySide('left') ?? tgt.getPorts()[0],
            sourceNodeId: src.id, targetNodeId: tgt.id, distance: 0,
          };
          engine.commandManager.execute(snap.buildProximityLinkCommand(candidate));
        }
        src = null;
      },
      onCancel: () => { src = null; },
    } as any);
    markReady();
  };
  return (
    <div style={{ height: '100vh' }}>
      <GrafloriaFlow defaultNodes={nodes} defaultEdges={edges} onInit={onInit} />
    </div>
  );
}

nodes/intersections.text:
import type { DiagramInstance } from '@grafloria/react';
import { GrafloriaFlow } from '@grafloria/react';
import { createDiagramApi } from '@grafloria/element';
import { markReady } from '../ready';

const nodes = [
  { id: 'a', position: { x: 120, y: 140 }, size: { width: 180, height: 110 }, label: 'A · drag me' },
  { id: 'b', position: { x: 460, y: 140 }, size: { width: 180, height: 110 }, label: 'B' },
  { id: 'c', position: { x: 800, y: 140 }, size: { width: 180, height: 110 }, label: 'C' },
  // Small enough to fit ENTIRELY inside another node (overlap vs containment).
  { id: 's', position: { x: 150, y: 430 }, size: { width: 60, height: 60 }, label: 'S' },
];
const edges: any[] = [];

// The shared highlight style. Identity (===) marks a highlight as ours.
const HILITE = { type: 'rect', fill: '#fecaca', stroke: '#dc2626' };
const rectOf = (n: any) => ({ x: n.position.x, y: n.position.y, width: n.size.width, height: n.size.height });

/** Drag a node and every node it overlaps lights up red, live — the public
 *  createDiagramApi(...).getIntersectingNodes wrapper on each move. */
export default function IntersectionsDemo() {
  const onInit = (instance: DiagramInstance) => {
    const model = instance.getModel() as any;
    const api = createDiagramApi(instance as any) as any;

    const hits = (id: string) => api
      .getIntersectingNodes(rectOf(model.getNode(id)))
      .filter((o: any) => o.id !== id)
      .map((o: any) => o.id);

    const relight = (movedId: string) => {
      const moved = model.getNode(movedId);
      if (!moved) return;
      const lit = hits(movedId);
      for (const n of model.getNodes()) {
        const want = lit.includes(n.id);
        const has = n.getMetadata('shape') === HILITE;
        if (want && !has) n.setMetadata('shape', HILITE);
        else if (!want && has) n.setMetadata('shape', undefined);
      }
    };
    model.on('node:moved', ({ nodeId }: any) => relight(nodeId));
    markReady();
  };
  return (
    <div style={{ height: '100vh' }}>
      <GrafloriaFlow defaultNodes={nodes} defaultEdges={edges} onInit={onInit} />
    </div>
  );
}

nodes/node-position-animation.text:
import { useRef, useState } from 'react';
import type { DiagramInstance } from '@grafloria/react';
import { GrafloriaFlow } from '@grafloria/react';
import { markReady } from '../ready';

const IDS = Array.from({ length: 8 }, (_, i) => `n${i}`);
const SIZE = { width: 96, height: 40 };
const HX = SIZE.width / 2, HY = SIZE.height / 2;
const CX = 600, CY = 285;

// Three target layouts as {id: {x,y}} of the node's top-left.
function circleLayout() { const o: any = {}; IDS.forEach((id, i) => { const a = (i / IDS.length) * 2 * Math.PI - Math.PI / 2; o[id] = { x: CX + 250 * Math.cos(a) - HX, y: CY + 205 * Math.sin(a) - HY }; }); return o; }
function gridLayout()   { const o: any = {}; IDS.forEach((id, i) => { const c = i % 4, r = (i / 4) | 0; o[id] = { x: (315 + c * 190) - HX, y: (160 + r * 250) - HY }; }); return o; }
function rowLayout()    { const o: any = {}; IDS.forEach((id, i) => { o[id] = { x: (90 + i * 145) - HX, y: CY - HY }; }); return o; }

const LAYOUTS: any = { grid: gridLayout(), circle: circleLayout(), row: rowLayout() };
const ORDER = ['grid', 'circle', 'row'];
const EDGES = IDS.map((id, i) => ({ id: `e${i}`, source: id, target: IDS[(i + 1) % IDS.length] })); // a ring
const NODES = IDS.map((id) => ({ id, position: { ...LAYOUTS.grid[id] }, size: SIZE, label: id.toUpperCase() }));

const easeOutCubic = (t: number) => 1 - Math.pow(1 - t, 3);

/** Eight nodes tween between layouts — grid · ring · row — by writing
 *  node.position every frame on an ease-out curve (pure userland). */
export default function NodePositionAnimationDemo() {
  const instanceRef = useRef<DiagramInstance | null>(null);
  const busy = useRef(false);
  const [current, setCurrent] = useState('grid');

  const onInit = (instance: DiagramInstance) => {
    instanceRef.current = instance;
    markReady();
  };

  const tweenTo = (targets: any, duration = 900) => new Promise<void>((resolve) => {
    const instance = instanceRef.current;
    if (!instance) return resolve();
    const model = instance.getModel() as any;
    const starts: any = {};
    for (const id of Object.keys(targets)) { const p = model.getNode(id).position; starts[id] = { x: p.x, y: p.y }; }
    const t0 = performance.now();
    const frame = (now: number) => {
      const raw = Math.min(1, (now - t0) / duration);
      const k = easeOutCubic(raw);
      instance.batchUpdate((m: any) => {
        for (const id of Object.keys(targets)) {
          const s = starts[id], t = targets[id];
          m.getNode(id).setPosition(s.x + (t.x - s.x) * k, s.y + (t.y - s.y) * k);
        }
      });
      instance.renderNow();
      if (raw < 1) requestAnimationFrame(frame); else resolve();
    };
    requestAnimationFrame(frame);
  });

  const shuffle = async () => {
    if (busy.current) return;
    busy.current = true;
    const next = ORDER[(ORDER.indexOf(current) + 1) % ORDER.length];
    setCurrent(next);
    await tweenTo(LAYOUTS[next]);
    busy.current = false;
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
      <div style={{ display: 'flex', gap: 16, alignItems: 'center', padding: '10px 24px',
        borderBottom: '1px solid rgba(127,127,127,.25)', font: '12px system-ui, sans-serif' }}>
        <button type="button" onClick={shuffle}
          style={{ font: '12px system-ui, sans-serif', padding: '4px 12px', border: '1px solid rgba(127,127,127,.5)', borderRadius: 6, background: 'transparent', color: 'inherit', cursor: 'pointer' }}>
          ▶ shuffle layout
        </button>
        <span style={{ opacity: 0.7 }}>layout: {current}</span>
      </div>
      <div style={{ flex: 1 }}>
        <GrafloriaFlow defaultNodes={NODES} defaultEdges={EDGES} onInit={onInit} />
      </div>
    </div>
  );
}

