interaction/computing-flows.text:
import { useRef } from 'react';
import type { DiagramInstance } from '@grafloria/react';
import { GrafloriaFlow } from '@grafloria/react';
import { markReady } from '../ready';

const nodes: any[] = [
  { id: 'in',  position: { x: 40,  y: 120 }, size: { width: 120, height: 56 }, label: 'input',
    ports: [{ id: 'in.out', side: 'right', type: 'output', dataType: 'number' }], data: { value: 2 } },
  { id: 'mul', position: { x: 240, y: 120 }, size: { width: 120, height: 56 }, label: '× 3',
    ports: [{ id: 'mul.in', side: 'left', type: 'input', dataType: 'number' },
            { id: 'mul.out', side: 'right', type: 'output', dataType: 'number' }], data: { op: 'mul', k: 3, value: 0 } },
  { id: 'add', position: { x: 440, y: 120 }, size: { width: 120, height: 56 }, label: '+ 10',
    ports: [{ id: 'add.in', side: 'left', type: 'input', dataType: 'number' },
            { id: 'add.out', side: 'right', type: 'output', dataType: 'number' }], data: { op: 'add', k: 10, value: 0 } },
  { id: 'out', position: { x: 640, y: 120 }, size: { width: 120, height: 56 }, label: 'sink',
    ports: [{ id: 'out.in', side: 'left', type: 'input', dataType: 'number' }], data: { op: 'sink', value: 0 } },
];
const edges: any[] = [
  { id: 'l1', source: 'in',  target: 'mul', sourceHandle: 'in.out',  targetHandle: 'mul.in' },
  { id: 'l2', source: 'mul', target: 'add', sourceHandle: 'mul.out', targetHandle: 'add.in' },
  { id: 'l3', source: 'add', target: 'out', sourceHandle: 'add.out', targetHandle: 'out.in' },
];

/** Data flowing through typed ports: type a value and every downstream node
 *  recomputes LIVE along the real link topology. Grafloria owns the graph and
 *  fires the change events; the app owns the arithmetic. */
export default function ComputingFlowsDemo() {
  const srcRef = useRef<HTMLInputElement | null>(null);
  const formulaRef = useRef<HTMLSpanElement | null>(null);

  const onInit = (instance: DiagramInstance) => {
    const api = instance as any;
    const model = api.getModel();

    const report = () => {
      const v = (id: string) => model.getNode(id).data.value;
      if (formulaRef.current) formulaRef.current.textContent = `→  ×3=${v('mul')}  →  +10=${v('add')}  →  sink=${v('out')}`;
      if (srcRef.current && document.activeElement !== srcRef.current) srcRef.current.value = String(v('in'));
    };
    const propagate = () => {
      const order = ['in', 'mul', 'add', 'out'];
      const incoming = (nodeId: string) => model.getLinks().filter((l: any) => l.targetNodeId === nodeId);
      for (const id of order) {
        const node = model.getNode(id);
        if (id === 'in') continue;
        const feeds = incoming(id);
        const input = feeds.length ? (model.getNode(feeds[0].sourceNodeId)?.data.value ?? 0) : null;
        if (input === null) continue;
        const d = node.data;
        d.value = d.op === 'mul' ? input * d.k : d.op === 'add' ? input + d.k : input;
      }
      api.renderNow();
      report();
    };

    srcRef.current?.addEventListener('input', () => {
      const n = Number(srcRef.current!.value);
      model.getNode('in').data.value = Number.isFinite(n) ? n : 0;
      propagate();
    });
    model.on('link:added', () => propagate());
    model.on('link:removed', () => propagate());

    propagate();
    markReady();
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
      <div style={{ padding: '8px 24px', font: '12px/1.5 ui-monospace, monospace', opacity: 0.9,
        borderBottom: '1px solid rgba(127,127,127,.25)', display: 'flex', alignItems: 'center', gap: 14, flexWrap: 'wrap' }}>
        <label style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>input
          <input ref={srcRef} type="number" step={1} defaultValue={2}
            style={{ width: 74, font: 'inherit', padding: '2px 6px', border: '1px solid rgba(127,127,127,.5)', borderRadius: 4, background: 'transparent', color: 'inherit' }} />
        </label>
        <span ref={formulaRef} style={{ whiteSpace: 'pre' }} />
      </div>
      <div style={{ flex: 1 }}>
        <GrafloriaFlow defaultNodes={nodes} defaultEdges={edges} onInit={onInit} />
      </div>
    </div>
  );
}

interaction/connection-events.text:
import { useEffect, useRef } from 'react';
import type { DiagramInstance } from '@grafloria/react';
import { GrafloriaFlow } from '@grafloria/react';
import { markReady } from '../ready';

const nodes: any[] = [
  { id: 'src', position: { x: 80,  y: 70 }, size: { width: 150, height: 60 }, label: 'source',
    ports: [{ id: 'src.out', side: 'right', type: 'output' }] },
  { id: 'dst', position: { x: 430, y: 70 }, size: { width: 150, height: 60 }, label: 'target',
    ports: [{ id: 'dst.in', side: 'left', type: 'input' }] },
];
const edges: any[] = [];

const EVENTS: [string, (p: any) => string][] = [
  ['connection:start',      (p) => p?.sourcePort?.id ?? '?'],
  ['connection:update',     (p) => `${p?.targetPort?.id ?? '(none)'} ${p?.isValid ? 'ok' : 'no'}`],
  ['connection:port-enter', (p) => `${p?.port?.id ?? '?'} ${p?.isValid ? 'ok' : '✗ ' + (p?.rejectionReason ?? '')}`],
  ['connection:port-leave', (p) => p?.port?.id ?? '?'],
  ['connection:complete',   (p) => `${p?.sourcePortId ?? '?'} → ${p?.targetPortId ?? '?'}`],
  ['connection:cancel',     (p) => `${p?.sourcePort?.id ?? '?'} (abandoned / refused)`],
];

/** A live log of the connection lifecycle the engine fires as you drag a wire —
 *  start, per-move update, port enter/leave, then complete or cancel. */
export default function ConnectionEventsDemo() {
  const logRef = useRef<HTMLDivElement | null>(null);
  const disposers = useRef<Array<() => void>>([]);
  useEffect(() => () => disposers.current.forEach((d) => d?.()), []);

  const onInit = (instance: DiagramInstance) => {
    const engine = instance.getEngine() as any;
    const summaryOf = new Map(EVENTS);
    const logEl = logRef.current!;

    const logRow = (name: string, payload: any) => {
      const empty = logEl.querySelector('.empty');
      if (empty) empty.remove();
      const row = document.createElement('div');
      row.className = 'row';
      const summary = (summaryOf.get(name) || (() => ''))(payload);
      const ev = document.createElement('span');
      ev.textContent = name;
      ev.style.cssText = 'display:inline-block;min-width:168px;font-weight:600';
      const det = document.createElement('span');
      det.textContent = summary;
      row.appendChild(ev); row.appendChild(det);
      logEl.prepend(row);
      while (logEl.querySelectorAll('.row').length > 12) logEl.querySelector('.row:last-child')!.remove();
    };

    disposers.current = EVENTS.map(([name]) => engine.eventBus.on(name, (payload: any) => logRow(name, payload)));
    markReady();
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh' }}>
      <div style={{ padding: '8px 24px 10px', borderBottom: '1px solid rgba(127,127,127,.25)', font: '12px/1.4 ui-monospace, monospace' }}>
        <div ref={logRef} style={{ height: 88, overflowY: 'auto', whiteSpace: 'pre', opacity: 0.9 }}>
          <span className="empty" style={{ opacity: 0.5 }}>drag from the source&apos;s right port to see the connection lifecycle fire…</span>
        </div>
      </div>
      <div style={{ flex: 1 }}>
        <GrafloriaFlow defaultNodes={nodes} defaultEdges={edges} onInit={onInit} />
      </div>
    </div>
  );
}

interaction/context-menu.text:
import { useRef } from 'react';
import type { DiagramInstance } from '@grafloria/react';
import { GrafloriaFlow } from '@grafloria/react';
import { markReady } from '../ready';

const nodes: any[] = [
  { id: 'a', position: { x: 120, y: 120 }, size: { width: 120, height: 48 }, label: 'Alpha' },
  { id: 'b', position: { x: 380, y: 120 }, size: { width: 120, height: 48 }, label: 'Beta' },
];
const edges: any[] = [{ id: 'e', source: 'a', target: 'b' }];

/** Right-click a node for Rename / Duplicate / Delete — driven by a real
 *  contextmenu event, and every item actually mutates the model it names. */
export default function ContextMenuDemo() {
  const wrapRef = useRef<HTMLDivElement | null>(null);
  const menuRef = useRef<HTMLDivElement | null>(null);
  const targetRef = useRef<string | null>(null);

  const onInit = (instance: DiagramInstance) => {
    const host = wrapRef.current!;
    const menu = menuRef.current!;
    const api = instance as any;
    const model = api.getModel();
    const engine = instance.getEngine() as any;

    host.addEventListener('contextmenu', (e) => {
      const el = (e.target as HTMLElement).closest('[data-node-id]');
      if (!el) return;
      e.preventDefault();
      targetRef.current = el.getAttribute('data-node-id');
      const rect = host.getBoundingClientRect();
      menu.style.left = `${e.clientX - rect.left}px`;
      menu.style.top = `${e.clientY - rect.top}px`;
      menu.classList.add('open');
      menu.style.display = 'block';
    });

    const act = async (action: string) => {
      const id = targetRef.current!;
      if (action === 'rename') model.getNode(id).setMetadata('label', 'RENAMED');
      if (action === 'delete') model.removeNode(id);
      if (action === 'duplicate') {
        const src = model.getNode(id);
        const copy = await engine.addNode({ type: 'rect', position: { x: src.position.x + 30, y: src.position.y + 60 }, size: { ...src.size } });
        copy.setMetadata('label', (src.getMetadata('label') ?? '') + ' copy');
      }
      menu.classList.remove('open');
      menu.style.display = 'none';
      api.renderNow();
    };
    for (const btn of Array.from(menu.querySelectorAll('button'))) {
      btn.addEventListener('click', () => act((btn as HTMLElement).dataset.act!));
    }
    document.addEventListener('pointerdown', (e) => {
      if (!menu.contains(e.target as Node)) { menu.classList.remove('open'); menu.style.display = 'none'; }
    });
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape') { menu.classList.remove('open'); menu.style.display = 'none'; }
    });
    markReady();
  };

  const btn = { display: 'block', width: '100%', textAlign: 'left' as const, padding: '7px 10px',
    border: 0, background: 'transparent', color: 'inherit', borderRadius: 5, cursor: 'pointer' };

  return (
    <div ref={wrapRef} style={{ height: '100vh', position: 'relative' }}>
      <div ref={menuRef} style={{ position: 'absolute', zIndex: 10, minWidth: 160, background: 'var(--mbg,#1a1a1a)',
        color: 'inherit', border: '1px solid rgba(127,127,127,.35)', borderRadius: 8, boxShadow: '0 8px 30px rgba(0,0,0,.18)',
        padding: 4, display: 'none', font: '13px system-ui, sans-serif' }}>
        <button data-act="rename" style={btn}>Rename</button>
